import React, { Component } from "react"
import { AnchorLink } from "gatsby-plugin-anchor-links";


class Navigation extends Component  {

    constructor(props) {
        super(props);
        this.state = {}
        this.uncheck = this.uncheck.bind(this);
    };

    uncheck() {
        document.getElementById("nav-toggle").checked = false;
    }

  

    render() {

        return(
                <div className="navigation">
                    <input type="checkbox" className="navigation__checkbox" id="nav-toggle"/>
                    <label htmlFor="nav-toggle" className="navigation__button">
                        <span className="navigation__icon">&nbsp;</span>
                    </label>

                    <div className="navigation__bg"></div>

                    <nav className="navigation__nav">
                        <ul className="navigation__list">
                            <li className="navigation__item" onClick={this.uncheck}><AnchorLink className="navigation__link" to="/#skills" onClick={this.uncheck}>Habilidades</AnchorLink></li>
                            <li className="navigation__item" onClick={this.uncheck}><AnchorLink className="navigation__link" to="#" onClick={this.uncheck}>Projetos</AnchorLink></li>
                            <li className="navigation__item" onClick={this.uncheck}><AnchorLink className="navigation__link" to="#" onClick={this.uncheck}>Sobre mim</AnchorLink></li>
                                
                        </ul>
                    </nav>

                </div>
        )
    }
}

export default Navigation