import React, { Component } from "react"
import Navigation from "./navigation"
import { AnchorLink } from "gatsby-plugin-anchor-links";


class Navbar extends Component  {

    constructor(props) {
        super(props);
        this.state = {}
    };

  

    render() {

        return(
                <nav className="navbar">
                    <div className="navbar__content">
                        <h2 className="navbar__content__logo">Tiago Murer</h2>
                        <ul className="navbar__content__links">
                            <li><AnchorLink to="/#skills">Habilidades</AnchorLink></li>
                            <li><AnchorLink to="/#skills">Projetos</AnchorLink></li>
                            <li><AnchorLink to="/#skills">Sobre mim</AnchorLink></li>
                        </ul>
                        <Navigation className="navbar__content__navigation"/>
                    </div>
                </nav>
        )
    }
}

export default Navbar